/// BTTag / BTTagGroup — pill label atoms (Figma 3050-6361 / 3050-6644).
library;

export 'tag.types.dart';
export 'tag.widget.dart';
export 'tag_group.widget.dart';

/// BTTag types — shared by [BTTag] and [BTTagGroup].
///
/// Figma nodes 3050-6361 / 3050-6644.
library;

/// BTTagVariant — visual style of the tag.
enum BTTagVariant {
  /// Solid light background (default).
  defaultVariant,

  /// Transparent with border.
  outline,
}

/// Data model for a single tag in [BTTagGroup].
class BTTagItem {
  const BTTagItem({required this.label, this.id});

  /// Text label shown inside the tag.
  final String label;

  /// Optional identifier for keying; defaults to [label] if null.
  final String? id;

  /// Effective key — uses [id] when set, otherwise falls back to [label].
  String get effectiveId => id ?? label;
}

/// Layout mode for [BTTagGroup].
enum BTTagGroupType {
  /// Single scrollable row — tags never wrap.
  scroll,

  /// Tags wrap onto multiple lines.
  wrap,
}

/// Gap between tags in [BTTagGroup].
enum BTTagGroupSpacing {
  /// 4 px gap (default).
  defaultSpacing,

  /// 8 px gap.
  loose,
}

/// BTTag — removable pill label atom.
/// Figma node 3050-6361.
///
/// ## Usage
/// ```dart
/// // Simple tag, no remove
/// BTTag(label: 'Flutter')
///
/// // Tag with left icon and remove callback
/// BTTag(
///   label: 'Vue',
///   leftIcon: const Icon(Icons.circle, size: 16),
///   onRemove: () => setState(() => tags.remove('Vue')),
/// )
///
/// // Outline variant
/// BTTag(label: 'React', variant: BTTagVariant.outline)
/// ```
library;

import 'package:btech_tokens/btech_tokens.dart';
import 'package:btech_ui/src/components/atoms/tag/tag.types.dart';
import 'package:flutter/material.dart';

/// Removable pill label atom. See file header for usage examples.
class BTTag extends StatefulWidget {
  const BTTag({
    required this.label,
    this.variant = BTTagVariant.defaultVariant,
    this.leftIcon,
    this.onRemove,
    super.key,
  });

  /// Text shown inside the tag.
  final String label;

  /// Visual style — default (solid) or outline.
  final BTTagVariant variant;

  /// Optional 16×16 widget shown to the left of [label].
  final Widget? leftIcon;

  /// When set, renders a close (cancel) button on the right.
  /// Calling [onRemove] should remove this tag from the parent list.
  final VoidCallback? onRemove;

  @override
  State<BTTag> createState() => _BTTagState();
}

class _BTTagState extends State<BTTag> {
  bool _isHovered = false;

  @override
  Widget build(BuildContext context) {
    final c = context.btColor;
    final isOutline =
        widget.variant == BTTagVariant.outline;

    // Background: transparent by default for outline; subtler otherwise.
    // Hover shifts to subtlest (default) or subtle (outline).
    final Color? bgColor;
    if (isOutline) {
      bgColor = _isHovered ? c.bg.subtle : null;
    } else {
      bgColor =
          _isHovered ? c.bg.subtlest : c.bg.subtler;
    }

    return MouseRegion(
      cursor: widget.onRemove != null
          ? SystemMouseCursors.click
          : MouseCursor.defer,
      onEnter: (_) => setState(() => _isHovered = true),
      onExit: (_) => setState(() => _isHovered = false),
      child: Container(
        padding: EdgeInsets.symmetric(
          vertical: BTSpacing.s2xs,
          horizontal: BTSpacing.xs,
        ),
        decoration: BoxDecoration(
          color: bgColor,
          borderRadius:
              BorderRadius.circular(BTRadius.sm),
          border: isOutline
              ? Border.all(color: c.border.secondary)
              : null,
        ),
        child: Row(
          mainAxisSize: MainAxisSize.min,
          children: [
            if (widget.leftIcon != null) ...[
              IconTheme(
                data: IconThemeData(
                  size: 16,
                  color: c.text.primary,
                ),
                child: widget.leftIcon!,
              ),
              SizedBox(width: BTSpacing.xs),
            ],
            Text(
              widget.label,
              style: TextStyle(
                fontFamily: BTTypography.fontFamily,
                fontSize: 12.0,
                fontWeight: FontWeight.w500,
                height: 16 / 12,
                letterSpacing: 0,
                color: c.text.primary,
              ),
            ),
            if (widget.onRemove != null) ...[
              SizedBox(width: BTSpacing.xs),
              GestureDetector(
                onTap: widget.onRemove,
                child: Icon(
                  Icons.cancel,
                  size: 16,
                  color: c.text.primary,
                ),
              ),
            ],
          ],
        ),
      ),
    );
  }
}

/// BTTagGroup — layout wrapper for a list of [BTTag] widgets.
/// Figma node 3050-6644.
///
/// Renders tags in either a scrollable row (scroll) or a
/// wrapping grid (wrap). Gap between tags is 4 px (default)
/// or 8 px (loose).
///
/// ## Usage
/// ```dart
/// BTTagGroup(
///   items: const [
///     BTTagItem(label: 'Flutter'),
///     BTTagItem(label: 'React'),
///   ],
///   onRemove: (item, index) =>
///       setState(() => _tags.removeAt(index)),
/// )
///
/// // Wrapping layout, outline variant
/// BTTagGroup(
///   items: _tags,
///   variant: BTTagVariant.outline,
///   type: BTTagGroupType.wrap,
///   spacing: BTTagGroupSpacing.loose,
///   onRemove: (item, index) =>
///       setState(() => _tags.removeAt(index)),
/// )
/// ```
library;

import 'package:btech_tokens/btech_tokens.dart';
import 'package:btech_ui/src/components/atoms/tag/tag.types.dart';
import 'package:btech_ui/src/components/atoms/tag/tag.widget.dart';
import 'package:flutter/material.dart';

/// Layout wrapper that renders a list of [BTTag] items.
/// See file header for usage examples.
class BTTagGroup extends StatelessWidget {
  const BTTagGroup({
    required this.items,
    this.variant = BTTagVariant.defaultVariant,
    this.type = BTTagGroupType.scroll,
    this.spacing = BTTagGroupSpacing.defaultSpacing,
    this.onRemove,
    super.key,
  });

  /// Tags to display.
  final List<BTTagItem> items;

  /// Visual style applied to every tag in the group.
  final BTTagVariant variant;

  /// Layout mode — single scrollable row or multi-line wrap.
  final BTTagGroupType type;

  /// Gap between tags.
  final BTTagGroupSpacing spacing;

  /// Called when the user taps the close button of a tag.
  /// [item] is the removed tag; [index] is its position.
  /// The caller must update [items] to reflect the removal.
  final void Function(BTTagItem item, int index)? onRemove;

  @override
  Widget build(BuildContext context) {
    final gap = spacing == BTTagGroupSpacing.loose
        ? BTSpacing.sm
        : BTSpacing.xs;

    final tags = List.generate(items.length, (i) {
      final item = items[i];
      return BTTag(
        key: ValueKey(item.effectiveId),
        label: item.label,
        variant: variant,
        onRemove: onRemove != null
            ? () => onRemove!(item, i)
            : null,
      );
    });

    if (type == BTTagGroupType.wrap) {
      return Wrap(
        spacing: gap,
        runSpacing: gap,
        children: tags,
      );
    }

    // Scroll mode — single horizontal row.
    return SingleChildScrollView(
      scrollDirection: Axis.horizontal,
      child: Row(
        mainAxisSize: MainAxisSize.min,
        children: [
          for (int i = 0; i < tags.length; i++) ...[
            tags[i],
            if (i < tags.length - 1)
              SizedBox(width: gap),
          ],
        ],
      ),
    );
  }
}
